#include <stdio.h>

int main()
{
	long long int a, b;
	long long int ZA[10];

	for (a = 2; a < 10; ZA[a++] = 0);
	scanf("%lld%lld", &a, &b);
	while (b) {
		if (b % 10 == 2)
			ZA[2] += 1;
		else if (b % 10 == 3)
			ZA[3] += 1;
		else if (b % 10 == 4) {
			ZA[2] += 2;
			ZA[3] += 1;
		} else if (b % 10 == 5)
			ZA[5] += 1;
		else if (b % 10 == 6) {
			ZA[5] += 1;
			ZA[3] += 1;
		} else if (b % 10 == 7)
			ZA[7] += 1;
		else if (b % 10 == 8) {
			ZA[2] += 3;
			ZA[7] += 1;
		} else if (b % 10 == 9) {
			ZA[2] += 1;
			ZA[3] += 2;
			ZA[7] += 1;
		}
		b /= 10;
	}
	for (a = 9; a > 1; --a)
		while (ZA[a]-- > 0)
			printf("%lld", a);
	printf("\n");

	return 0;
}

